import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Helmet } from 'react-helmet-async';
import { motion } from 'framer-motion';
import { supabase } from '../config/supabase';
import { useAuth } from '../contexts/AuthContext';
import HeritageGallery from '../components/layout/HeritageGallery';
import ScrollingProposals from '../components/home/ScrollingProposals';

const Home = () => {
  const { t } = useTranslation();
  const { isAuthenticated } = useAuth();
  const navigate = useNavigate();
  
  const [stats, setStats] = useState({
    citizens: 0,
    proposals: 0,
    votes: 0,
    yesPercentage: 0
  });
  
  const [liveCitizens, setLiveCitizens] = useState(0);

  // Fetch initial stats
  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [citizensRes, proposalsRes, votesRes] = await Promise.all([
          supabase.from('profiles').select('id', { count: 'exact', head: true }),
          supabase.from('proposals').select('id', { count: 'exact', head: true }).eq('status', 'published'),
          supabase.from('votes').select('id', { count: 'exact', head: true })
        ]);

        const totalCitizens = citizensRes.count || 0;
        const totalProposals = proposalsRes.count || 0;
        const totalVotes = votesRes.count || 0;

        setStats({
          citizens: totalCitizens,
          proposals: totalProposals,
          votes: totalVotes,
          yesPercentage: 50 // Default
        });
        
        setLiveCitizens(totalCitizens);
      } catch (error) {
        console.error('Error fetching stats:', error);
      }
    };

    fetchStats();
  }, []);

  // Live citizen counter - increments every 5 seconds
  useEffect(() => {
    const interval = setInterval(() => {
      setLiveCitizens(prev => prev + 1);
    }, 5000);
    
    return () => clearInterval(interval);
  }, []);

  const handleParticipate = () => {
    if (isAuthenticated) {
      navigate('/submit-proposal');
    } else {
      navigate('/register');
    }
  };

  return (
    <>
      <Helmet>
        <title>MAONI - Réforme Constitutionnelle RDC | v100.04</title>
        <meta name="description" content="Plateforme nationale de consultation citoyenne pour la réforme constitutionnelle en République Démocratique du Congo. La voix de 80 millions de Congolais." />
      </Helmet>

      {/* Hero Section */}
      <section className="hero">
        <motion.div 
          className="hero-content"
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
        >
          <img 
            src="/images/logo-drc-map.png" 
            alt="MAONI DRC" 
            className="hero-logo"
          />
          
          <h1 className="hero-title">
            MA<span style={{ color: 'var(--drc-yellow)' }}>O</span>NI
            <span>{t('home.hero.subtitle')}</span>
          </h1>
          
          <p className="hero-subtitle">
            Plateforme présidentielle de consultation citoyenne pour la réforme constitutionnelle.
            Votre voix compte pour l'avenir de la République Démocratique du Congo.
          </p>

          {/* Live Stats Counters */}
          <div className="hero-stats">
            <motion.div 
              className="hero-stat"
              whileHover={{ scale: 1.05 }}
              transition={{ type: "spring", stiffness: 300 }}
            >
              <div className="hero-stat-number">
                {liveCitizens.toLocaleString('fr-FR')}
              </div>
              <div className="hero-stat-label">{t('home.citizens')}</div>
            </motion.div>
            
            <motion.div 
              className="hero-stat"
              whileHover={{ scale: 1.05 }}
            >
              <div className="hero-stat-number">
                {stats.proposals.toLocaleString('fr-FR')}
              </div>
              <div className="hero-stat-label">{t('home.proposals')}</div>
            </motion.div>
            
            <motion.div 
              className="hero-stat"
              whileHover={{ scale: 1.05 }}
            >
              <div className="hero-stat-number">
                {stats.votes.toLocaleString('fr-FR')}
              </div>
              <div className="hero-stat-label">{t('home.votes')}</div>
            </motion.div>
            
            <motion.div 
              className="hero-stat"
              whileHover={{ scale: 1.05 }}
            >
              <div className="hero-stat-number" style={{ color: 'var(--success)' }}>
                {stats.yesPercentage}%
              </div>
              <div className="hero-stat-label">Majorité OUI</div>
            </motion.div>
          </div>

          {/* CTA Buttons */}
          <div className="hero-cta">
            <motion.button
              className="btn btn-primary btn-lg"
              onClick={handleParticipate}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              🇨🇩 {t('home.hero.cta')}
            </motion.button>
            
            <motion.button
              className="btn btn-secondary btn-lg"
              onClick={() => navigate('/proposals')}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              📋 Consulter les propositions
            </motion.button>
          </div>
        </motion.div>
      </section>

      {/* Scrolling Proposals */}
      <section className="scrolling-proposals">
        <div className="container">
          <h2 className="scrolling-proposals-title">
            🔄 Propositions des citoyens
          </h2>
          <ScrollingProposals />
        </div>
      </section>

      {/* Heritage Gallery */}
      <section style={{ padding: 'var(--space-3xl) 0', background: 'var(--gray-50)' }}>
        <div className="container">
          <motion.h2 
            style={{ 
              textAlign: 'center', 
              marginBottom: 'var(--space-2xl)',
              color: 'var(--drc-blue)',
              fontFamily: 'var(--font-display)',
              fontSize: '2rem'
            }}
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6 }}
          >
            🇨🇩 Patrimoine National
          </motion.h2>
          <HeritageGallery />
        </div>
      </section>

      {/* Features Section */}
      <section style={{ padding: 'var(--space-3xl) 0', background: 'white' }}>
        <div className="container">
          <motion.h2 
            style={{ 
              textAlign: 'center', 
              marginBottom: 'var(--space-2xl)',
              color: 'var(--drc-blue)',
              fontFamily: 'var(--font-display)',
              fontSize: '2rem'
            }}
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            viewport={{ once: true }}
          >
            Comment ça marche ?
          </motion.h2>
          
          <div style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--space-xl)'
          }}>
            {[
              {
                icon: '📝',
                title: '1. Proposez',
                description: 'Soumettez vos idées pour améliorer la constitution. Chaque voix compte pour construire l\'avenir de la RDC.'
              },
              {
                icon: '🗳️',
                title: '2. Votez',
                description: 'Exprimez votre soutien ou opposition aux propositions des autres citoyens. Votez OUI ou NON en un clic.'
              },
              {
                icon: '📊',
                title: '3. Consultez',
                description: 'Suivez les résultats en temps réel, les tendances par province et les statistiques nationales.'
              },
              {
                icon: '🏛️',
                title: '4. Impactez',
                description: 'Les propositions les plus soutenues seront transmises au Département Présidentiel pour examen.'
              }
            ].map((feature, index) => (
              <motion.div
                key={feature.title}
                style={{
                  padding: 'var(--space-xl)',
                  background: 'var(--gray-50)',
                  borderRadius: 'var(--radius-xl)',
                  textAlign: 'center',
                  borderTop: '4px solid var(--drc-blue)'
                }}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ delay: index * 0.15, duration: 0.5 }}
                whileHover={{ 
                  y: -5, 
                  boxShadow: 'var(--shadow-xl)',
                  borderTopColor: 'var(--drc-yellow)'
                }}
              >
                <div style={{ fontSize: '3rem', marginBottom: 'var(--space-md)' }}>
                  {feature.icon}
                </div>
                <h3 style={{ 
                  marginBottom: 'var(--space-sm)',
                  color: 'var(--drc-blue)'
                }}>
                  {feature.title}
                </h3>
                <p style={{ color: 'var(--gray-600)', lineHeight: 1.7 }}>
                  {feature.description}
                </p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA Bottom Section */}
      <section style={{ 
        padding: 'var(--space-3xl) 0',
        background: 'linear-gradient(135deg, var(--drc-blue) 0%, var(--drc-blue-dark) 100%)',
        textAlign: 'center',
        color: 'white'
      }}>
        <div className="container">
          <motion.h2
            style={{ 
              fontSize: '2rem', 
              marginBottom: 'var(--space-lg)',
              fontFamily: 'var(--font-display)',
              color: 'white'
            }}
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
          >
            Prêt à faire entendre votre voix ?
          </motion.h2>
          <motion.p
            style={{ 
              fontSize: '1.2rem', 
              marginBottom: 'var(--space-xl)',
              opacity: 0.9,
              maxWidth: '600px',
              margin: '0 auto var(--space-xl)'
            }}
          >
            Rejoignez les millions de Congolais qui participent déjà à la construction 
            de l'avenir constitutionnel de notre pays.
          </motion.p>
          <motion.button
            className="btn btn-primary btn-xl"
            onClick={handleParticipate}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            🇨🇩 Je participe maintenant
          </motion.button>
        </div>
      </section>
    </>
  );
};

export default Home;
